final:
module SR_Latch (  
    input wire S,  
    input wire R,  
    output reg obf_Q,  
    output reg Qn  
);  
    always @ (S or R) begin  
        if (S && !R) begin  
            obf_Q = 1;  
            Qn = 0;  
        end else if (!S && R) begin  
            obf_Q = 0;  
            Qn = 1;  
        end else if (!S && !R) begin  
            obf_Q = obf_Q;  // Hold state  
            Qn = ~obf_Q;  
        end else begin  
            obf_Q = 1'bx;  // Invalid state  
            Qn = 1'bx;  
        end  
    end  
endmodule
